class Solution:
    def shoppingOffers(self, price, special, needs):
        n = len(price)
        best = {}
        def solve(state):
            if state in best:
                return best[state]
            base = sum(state[i] * price[i] for i in range(n))
            res = base
            for off in special:
                ns = list(state)
                ok = True
                for i in range(n):
                    ns[i] -= off[i]
                    if ns[i] < 0:
                        ok = False
                        break
                if ok:
                    res = min(res, off[n] + solve(tuple(ns)))
            best[state] = res
            return res
        return solve(tuple(needs))

