class Solution:
    def shoppingOffers(self, price, special, needs):
        n = len(price)
        from functools import lru_cache
        offers = [o for o in special]
        @lru_cache(maxsize=None)
        def dfs(state):
            cost = sum(state[i] * price[i] for i in range(n))
            for off in offers:
                nxt = []
                ok = True
                for i in range(n):
                    v = state[i] - off[i]
                    if v < 0:
                        ok = False
                        break
                    nxt.append(v)
                if ok:
                    cost = min(cost, off[n] + dfs(tuple(nxt)))
            return cost
        return dfs(tuple(needs))

