var shoppingOffers = function(price, special, needs) {
    const n = price.length;
    const memo = new Map();
    const dfs = (state) => {
        const key = state.join(',');
        if (memo.has(key)) return memo.get(key);
        let cost = 0;
        for (let i = 0; i < n; i++) cost += state[i] * price[i];
        for (const off of special) {
            const nxt = [];
            let ok = true;
            for (let i = 0; i < n; i++) {
                const v = state[i] - off[i];
                if (v < 0) { ok = false; break; }
                nxt.push(v);
            }
            if (ok) cost = Math.min(cost, off[n] + dfs(nxt));
        }
        memo.set(key, cost);
        return cost;
    };
    return dfs(needs.slice());
};
